//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "OPC core properties part + WordprocessingML metadata (docProps)
//! round-trip".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO/IEC 29500 / MS-OI29500 about the OPC Core Properties part and the
//! WordprocessingML docProps round-trip. A FAILING assertion here is NOT a flaky
//! test to be relaxed — it encodes a real Word-compliance gap in the stemma
//! engine (stemma diverges from how real Microsoft Word reads/writes the
//! package). Fix the engine (or, if the test mis-states the spec, the test), but
//! never weaken an assertion to make it green.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim, so re-serialising an unedited package reflects stemma's
//! verbatim-preservation contract, not Word's save normalisation. These specs
//! therefore assert opens-clean validity (and exercise the typed metadata EDIT
//! path where a property is authored), never `xmlOmits` on a verbatim-preserved
//! attribute. Substantive "what does Word write on save" claims are recorded as
//! ORACLE notes in each test's doc-comment and are left to the Word-oracle tier.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-.docx plumbing (mirrors the shared spec-suite prelude) ───

/// Build a valid minimal .docx. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` is a list of
/// `(part_path, xml)` written verbatim into the zip; for each known extra part a
/// matching content-type Override is emitted so the package stays valid.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Build content-type overrides for any extra parts we recognise.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let ct = match *path {
            "word/styles.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml")
            }
            "word/numbering.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml")
            }
            "docProps/core.xml" => {
                Some("application/vnd.openxmlformats-package.core-properties+xml")
            }
            "docProps/custom.xml" => {
                Some("application/vnd.openxmlformats-officedocument.custom-properties+xml")
            }
            "docProps/app.xml" => {
                Some("application/vnd.openxmlformats-officedocument.extended-properties+xml")
            }
            _ => None,
        };
        if let Some(ct) = ct {
            overrides.push_str(&format!(
                r#"<Override PartName="/{path}" ContentType="{ct}"/>"#
            ));
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    // Root rels: always the main document; add a core-properties relationship if
    // a core.xml extra part is present (so the package is wired the way Word
    // expects). Custom/app props are related from the document, but core is
    // related from the package root.
    let mut root_rels = String::from(
        r#"<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>"#,
    );
    let mut doc_rels = String::new();
    let mut next_doc_rel = 100u32;
    for (path, _) in extra_parts {
        match *path {
            "docProps/core.xml" => root_rels.push_str(
                r#"<Relationship Id="rIdCore" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/>"#,
            ),
            "docProps/custom.xml" => {
                root_rels.push_str(
                    r#"<Relationship Id="rIdCustom" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/custom-properties" Target="docProps/custom.xml"/>"#,
                );
            }
            "docProps/app.xml" => root_rels.push_str(
                r#"<Relationship Id="rIdApp" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/>"#,
            ),
            "word/styles.xml" => {
                doc_rels.push_str(&format!(
                    r#"<Relationship Id="rId{next_doc_rel}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>"#
                ));
                next_doc_rel += 1;
            }
            "word/numbering.xml" => {
                doc_rels.push_str(&format!(
                    r#"<Relationship Id="rId{next_doc_rel}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering" Target="numbering.xml"/>"#
                ));
                next_doc_rel += 1;
            }
            _ => {}
        }
    }

    let rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{root_rels}</Relationships>"#
    );
    let doc_rels_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels_xml.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    String::from_utf8_lossy(
        archive
            .get("word/document.xml")
            .expect("document.xml present"),
    )
    .into_owned()
}

/// Parse → serialize(default) → return the re-emitted `word/document.xml`.
/// VALID only for markup stemma's serializer actively generates/restructures
/// (ordering, structural synthesis, opens-clean validity) — never for asserting
/// that a verbatim-preserved value is normalised away.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// Read `docProps/core.xml` from a package if present.
#[allow(dead_code)]
fn core_xml_of(docx: &[u8]) -> Option<String> {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    archive
        .get("docProps/core.xml")
        .map(|b| String::from_utf8_lossy(b).into_owned())
}

/// Read `docProps/custom.xml` from a package if present.
#[allow(dead_code)]
fn custom_xml_of(docx: &[u8]) -> Option<String> {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    archive
        .get("docProps/custom.xml")
        .map(|b| String::from_utf8_lossy(b).into_owned())
}

/// Assert `validate` reports no errors on `bytes`, with a rule-bearing message.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{msg} — validate reported: ok={}, issues={:?}",
        report.ok,
        report.issues
    );
}

