const BODY_NO_CORE: &str =
    "<w:p><w:r><w:t>Document with no core properties part.</w:t></w:r></w:p><w:sectPr/>";

/// A package with NO Core Properties part must round-trip without one being
/// invented, and the result must still open clean.
/// Refs: ECMA-376 §8.2 (Core Properties part); ISO/IEC 29500-2 §8.2;
///       ISO/IEC 29500-1 §11.3.
#[test]
fn no_core_props_part_not_invented_on_roundtrip() {
    let bytes = make_docx(BODY_NO_CORE, &[]);
    let out = Document::parse(&bytes)
        .expect("parse")
        .serialize(&ExportOptions::default())
        .expect("serialize");

    // §8.2: a package with no Core Properties part is fully valid (at most one,
    // not at least one); stemma's output must validate without errors.
    assert_opens_clean(
        &out,
        "ECMA-376 §8.2 / ISO/IEC 29500-2 §8.2 / 29500-1 §11.3: a package with no \
         Core Properties part is valid (at-most-one, not at-least-one); the \
         serialized output must open clean",
    );

    // No-fallback (CLAUDE.md prime directive): stemma must not synthesize a
    // core-properties part for a document that never had one.
    assert!(
        core_xml_of(&out).is_none(),
        "ECMA-376 §8.2: stemma must NOT invent docProps/core.xml for a package \
         that never carried one (no-fallback directive); found a synthesized \
         core-properties part on round-trip",
    );
}

/// When stemma serializes dcterms:created/modified, the element must carry
/// xsi:type="dcterms:W3CDTF" and bind dcterms to http://purl.org/dc/terms/.
/// Refs: ECMA-376 §8.3.4 (Core property elements); ISO/IEC 29500-2 §8.3.4.
/// ORACLE: real Word opens the produced core.xml without repair; omitting
/// xsi:type makes Word flag the core-properties part.
#[test]
fn dcterms_date_requires_w3cdtf_xsi_type() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body with W3CDTF date metadata.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    // Exercise the typed EDIT path so stemma actively emits dcterms:created.
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("created", "2026-06-08T00:00:00Z")
        .expect("set created");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ECMA-376 §8.3.4 / ISO/IEC 29500-2 §8.3.4: created/modified without \
         xsi:type=\"dcterms:W3CDTF\" are schema-invalid; a package whose core.xml \
         emits these dates must validate clean, which presupposes the mandatory \
         xsi:type is present",
    );

    // Serializer-emits surface: stemma actively builds dcterms:created here, so
    // the emitted core.xml is fair game for an XML assertion.
    let core = core_xml_of(&out)
        .expect("ECMA-376 §8.3.4: set_core_property(created) must produce docProps/core.xml");
    assert!(
        core.contains("dcterms:W3CDTF"),
        "ECMA-376 §8.3.4 / ISO/IEC 29500-2 §8.3.4: the dcterms:created element \
         stemma emits must carry xsi:type=\"dcterms:W3CDTF\"; core.xml was: {core}",
    );
    assert!(
        core.contains("http://purl.org/dc/terms/"),
        "ECMA-376 §8.3.4: the dcterms prefix must be bound to \
         http://purl.org/dc/terms/ so the W3CDTF QName resolves; core.xml was: {core}",
    );
}

/// The coreProperties root stemma serializes must declare only namespaces and
/// carry no (non-namespace) attributes.
/// Refs: ECMA-376 §8.3.3 (coreProperties element); ISO/IEC 29500-2 §8.3.3.
/// ORACLE: Word opens a namespace-only coreProperties root without repair; a
/// stray root attribute triggers a repair.
#[test]
fn core_props_root_has_no_attributes() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body whose package core props root is attribute-free.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    // Author a property so stemma actively builds the coreProperties root.
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("title", "Root Attribute Test")
        .expect("set title");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ECMA-376 §8.3.3 / ISO/IEC 29500-2 §8.3.3: an attribute on the \
         coreProperties root is schema-invalid; the serialized package must \
         validate clean, which requires the root to be attribute-free",
    );

    // Serializer-emits: inspect the actively-built root. Strip namespace
    // declarations (xmlns / xmlns:*) and assert no other attributes survive on
    // the coreProperties start tag.
    let core = core_xml_of(&out)
        .expect("ECMA-376 §8.3.3: set_core_property must produce docProps/core.xml");
    let open = core
        .find("coreProperties")
        .and_then(|s| core[s..].find('>').map(|e| &core[s..s + e]))
        .expect("coreProperties start tag present");
    // Tokens after the element name: each must be a namespace declaration.
    let attrs: Vec<&str> = open.split_whitespace().skip(1).collect();
    for attr in &attrs {
        assert!(
            attr.starts_with("xmlns:") || attr.starts_with("xmlns="),
            "ECMA-376 §8.3.3: the coreProperties root must carry only namespace \
             declarations; found non-namespace attribute `{attr}` in start tag \
             `{open}`",
        );
    }
}

/// The dc: core-property elements (dc:title, dc:creator, …) stemma serializes
/// must be bare text with no xsi:type and no xml:lang attribute.
/// Refs: ECMA-376 §8.3.4 (dc: namespace); ISO/IEC 29500-2 §8.3.4.
/// ORACLE: Word writes bare <dc:title>text</dc:title>; xsi:type/xml:lang on a
/// dc: element repairs in Word (unlike dcterms:created which requires xsi:type).
#[test]
fn dc_core_elements_carry_no_xsi_type_or_lang() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body with a bare dc:title metadata field.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("title", "Bare Title")
        .expect("set title");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ECMA-376 §8.3.4 / ISO/IEC 29500-2 §8.3.4: a dc: element bearing xsi:type \
         or xml:lang is schema-invalid; the serialized package must validate \
         clean, which presupposes those attributes are absent from dc:title",
    );

    // Serializer-emits: stemma actively builds dc:title; the dc:title start tag
    // must carry neither xsi:type nor xml:lang.
    let core = core_xml_of(&out)
        .expect("ECMA-376 §8.3.4: set_core_property(title) must produce docProps/core.xml");
    let title_open = core
        .find("<dc:title")
        .and_then(|s| core[s..].find('>').map(|e| &core[s..s + e]))
        .expect("dc:title start tag present");
    assert!(
        !title_open.contains("xsi:type"),
        "ECMA-376 §8.3.4: dc:title must NOT carry xsi:type (only dcterms dates \
         do); start tag was `{title_open}`",
    );
    assert!(
        !title_open.contains("xml:lang"),
        "ECMA-376 §8.3.4: dc:title must NOT carry xml:lang; start tag was \
         `{title_open}`",
    );
}

/// Setting one core property must preserve the package's other already-present
/// core-property elements that the verb does not author (contentStatus,
/// revision, version, lastPrinted).
/// Refs: ECMA-376 §8.3.4; ISO/IEC 29500-2 §8.3.4.
/// ORACLE: Word's File>Info edits a single field and leaves the rest intact;
/// stemma's nine-field model is suspected to DROP unmodeled fields on rewrite —
/// this test surfaces that divergence as missing elements in the rewritten part.
const CORE_WITH_EXTRA_FIELDS: &str = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:dcmitype="http://purl.org/dc/dcmitype/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Original</dc:title><cp:contentStatus>Draft</cp:contentStatus><cp:revision>3</cp:revision><cp:version>1.0</cp:version><cp:lastPrinted>2026-01-01T00:00:00Z</cp:lastPrinted></cp:coreProperties>"#;

#[test]
fn unmodeled_core_fields_preserved_across_property_edit() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body whose package core props carry revision and version.</w:t></w:r></w:p><w:sectPr/>",
        &[("docProps/core.xml", CORE_WITH_EXTRA_FIELDS)],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("title", "Edited")
        .expect("set title");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    // §8.3.4: the package must remain schema-valid after the title edit.
    assert_opens_clean(
        &out,
        "ECMA-376 §8.3.4 / ISO/IEC 29500-2 §8.3.4: after a title edit the \
         rewritten core part must remain schema-valid (no orphaned/duplicate \
         elements) so the package opens clean",
    );

    // Substantive Word-consumption claim: contentStatus/revision/version/
    // lastPrinted must SURVIVE a single-field edit (Word preserves them). These
    // live in a separate part the typed model rewrites, so we assert on the
    // re-emitted core.xml directly — a FAIL here is the lossy-nine-field gap.
    let core = core_xml_of(&out).expect("docProps/core.xml present after edit");
    assert!(
        core.contains("Draft"),
        "ECMA-376 §8.3.4: cp:contentStatus=Draft must survive a title edit (Word \
         preserves unmodeled core fields); core.xml was: {core}",
    );
    assert!(
        core.contains("<cp:revision>3</cp:revision>") || core.contains(">3<"),
        "ECMA-376 §8.3.4: cp:revision=3 must survive a title edit; core.xml was: {core}",
    );
    assert!(
        core.contains("<cp:version>1.0</cp:version>") || core.contains("1.0"),
        "ECMA-376 §8.3.4: cp:version=1.0 must survive a title edit; core.xml was: {core}",
    );
    assert!(
        core.contains("lastPrinted"),
        "ECMA-376 §8.3.4: cp:lastPrinted must survive a title edit; core.xml was: {core}",
    );
}

/// Every custom file property must carry pid >= 2; pid 0 and 1 are reserved.
/// Refs: ISO/IEC 29500-1 §22.3.2.2; MS-OI29500 §2.1.1724.
/// ORACLE: Word numbers the first user property pid=2; pid 0/1 makes Word
/// reject/repair the custom part.
#[test]
fn custom_property_pid_starts_at_two() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Custom-property carrier.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_custom_property("MatterNumber", "M-1")
        .expect("set custom property");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ISO/IEC 29500-1 §22.3.2.2 / MS-OI29500 §2.1.1724: a custom.xml whose \
         first property uses pid=2 is the only Word-valid numbering; the package \
         must open clean",
    );

    // Serializer-emits: stemma actively assigns pid; the first property's pid
    // must be 2 and no property may use pid 0 or 1.
    let custom = custom_xml_of(&out)
        .expect("MS-OI29500 §2.1.1724: set_custom_property must produce docProps/custom.xml");
    assert!(
        custom.contains(r#"pid="2""#),
        "MS-OI29500 §2.1.1724 (ISO 29500-1 §22.3.2.2): the first custom property \
         must carry pid=\"2\" (pid 0/1 are reserved); custom.xml was: {custom}",
    );
    assert!(
        !custom.contains(r#"pid="0""#) && !custom.contains(r#"pid="1""#),
        "MS-OI29500 §2.1.1724: no custom property may use the reserved pid 0 or 1; \
         custom.xml was: {custom}",
    );
}

/// Custom file property names are case-insensitively unique; setting a name that
/// differs only in case from an existing one must replace it, not append.
/// Refs: ISO/IEC 29500-1 §22.3.2.2; MS-OI29500 §2.1.1724.
/// ORACLE: Word treats 'Reviewer' and 'reviewer' as the same property; two
/// case-colliding names trigger a Word repair.
#[ignore = "GAP: custom-property names are case-insensitively unique (ISO 29500-1 §22.3.2.2 / MS-OI29500 §2.1.1724), so set_custom_property(\"reviewer\") after set_custom_property(\"Reviewer\") must REPLACE the existing property, leaving exactly one <property>. stemma matches case-SENSITIVELY and emits two case-colliding <property> elements, which is not Word-valid. Fix site: set_custom_property's name lookup (src/docprops.rs) must compare names case-insensitively. The expected count==1 is correct per spec."]
#[test]
fn custom_property_name_case_insensitive_unique() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Case-collision carrier.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_custom_property("Reviewer", "a")
        .expect("set Reviewer")
        .set_custom_property("reviewer", "b")
        .expect("set reviewer");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "MS-OI29500 §2.1.1724 (ISO 29500-1 §22.3.2.2): custom property names are \
         case-insensitively unique; a package with two case-colliding names is \
         not Word-valid",
    );

    // Substantive claim: after setting 'Reviewer' then 'reviewer', a Word-correct
    // engine keeps exactly ONE custom property (value b). Count <property ...>
    // elements in the custom part — two is the case-sensitive-match divergence.
    let custom = custom_xml_of(&out)
        .expect("MS-OI29500 §2.1.1724: set_custom_property must produce docProps/custom.xml");
    let count = custom.matches("<property").count();
    assert_eq!(
        count, 1,
        "MS-OI29500 §2.1.1724: setting 'reviewer' after 'Reviewer' must REPLACE \
         (case-insensitive uniqueness), leaving exactly one <property>; found \
         {count} in custom.xml: {custom}",
    );
    assert!(
        custom.contains(">b</") || custom.contains("\">b<"),
        "MS-OI29500 §2.1.1724: the surviving custom property must hold the latest \
         value (b); custom.xml was: {custom}",
    );
}

/// dcterms:created/modified must carry xsi:type="dcterms:W3CDTF" with the
/// dcterms prefix. (Sibling of dcterms_date_requires_w3cdtf_xsi_type, pinned via
/// the modified date.)
/// Refs: ISO/IEC 29500-2 §8.3.4.
#[test]
fn dcterms_dates_carry_w3cdtf_xsi_type() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Date-stamped metadata carrier.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("created", "2026-01-01T00:00:00Z")
        .expect("set created");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ISO/IEC 29500-2 §8.3.4: created without xsi:type=\"dcterms:W3CDTF\" is \
         schema-invalid; the package must open clean, which presupposes the \
         attribute is present",
    );

    let core = core_xml_of(&out)
        .expect("ISO/IEC 29500-2 §8.3.4: set_core_property(created) must produce core.xml");
    assert!(
        core.contains("dcterms:created") && core.contains("dcterms:W3CDTF"),
        "ISO/IEC 29500-2 §8.3.4: dcterms:created must carry \
         xsi:type=\"dcterms:W3CDTF\"; core.xml was: {core}",
    );
}

/// Setting dc:title must preserve every other core property already present,
/// including standard fields stemma does not model (revision, language,
/// identifier, etc.). Word treats a property edit as a targeted field write.
/// Refs: ISO/IEC 29500-2 §8.3.4; ECMA-376 §15.2.12.1.
/// ORACLE: after a title edit Word's File>Info still shows Revision/Language/
/// Identifier; stemma's 9-field model is suspected to drop them on rewrite.
const CORE_WITH_STANDARD_FIELDS: &str = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:dcmitype="http://purl.org/dc/dcmitype/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Original</dc:title><cp:revision>7</cp:revision><dc:language>en-US</dc:language><dc:identifier>DOC-42</dc:identifier></cp:coreProperties>"#;

#[test]
fn set_core_property_preserves_unmodeled_standard_fields() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body unaffected by a metadata edit.</w:t></w:r></w:p><w:sectPr/>",
        &[("docProps/core.xml", CORE_WITH_STANDARD_FIELDS)],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("title", "Edited")
        .expect("set title");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ISO/IEC 29500-2 §8.3.4 / ECMA-376 §15.2.12.1: after set_core_property \
         the rewritten core part must remain schema-valid so Word opens it \
         without repair (§8.3.1)",
    );

    let core = core_xml_of(&out).expect("docProps/core.xml present after edit");
    assert!(
        core.contains("Edited"),
        "ISO/IEC 29500-2 §8.3.4: the new dc:title must be written; core.xml: {core}",
    );
    assert!(
        core.contains("<cp:revision>7</cp:revision>") || core.contains(">7<"),
        "ISO/IEC 29500-2 §8.3.4: cp:revision=7 must survive a title edit (Word \
         keeps unmodeled standard fields); core.xml was: {core}",
    );
    assert!(
        core.contains("en-US"),
        "ISO/IEC 29500-2 §8.3.4: dc:language=en-US must survive a title edit; \
         core.xml was: {core}",
    );
    assert!(
        core.contains("DOC-42"),
        "ISO/IEC 29500-2 §8.3.4: dc:identifier=DOC-42 must survive a title edit; \
         core.xml was: {core}",
    );
}

/// set_core_property('created') must emit xsi:type="dcterms:W3CDTF" with the
/// dcterms prefix bound to http://purl.org/dc/terms/.
/// Refs: ISO/IEC 29500-2 §8.3.4; ECMA-376 §15.2.12.1.
#[test]
fn set_core_created_emits_w3cdtf_xsi_type() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body unaffected by a created-date metadata edit.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_core_property("created", "2024-01-01T00:00:00Z")
        .expect("set created");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ISO/IEC 29500-2 §8.3.4 / ECMA-376 §15.2.12.1: docProps/core.xml must \
         validate against opc-coreProperties.xsd (requires xsi:type=dcterms:W3CDTF \
         on dcterms:created) so Word opens the package without repair (§8.3.1)",
    );

    let core = core_xml_of(&out)
        .expect("ISO/IEC 29500-2 §8.3.4: set_core_property(created) must produce core.xml");
    assert!(
        core.contains("dcterms:W3CDTF"),
        "ISO/IEC 29500-2 §8.3.4: the emitted dcterms:created must carry \
         xsi:type=\"dcterms:W3CDTF\"; core.xml was: {core}",
    );
    assert!(
        core.contains("http://purl.org/dc/terms/"),
        "ISO/IEC 29500-2 §8.3.4: dcterms must be bound to http://purl.org/dc/terms/ \
         so the W3CDTF QName resolves; core.xml was: {core}",
    );
}

/// Every <property> in docProps/custom.xml must carry both fmtid (ST_Guid) and
/// pid (xsd:int) — both use="required" in CT_Property.
/// Refs: ECMA-376 §22.3.2.2; Annex A.6.3 (shared-documentPropertiesCustom.xsd).
#[test]
fn custom_property_emits_required_fmtid_and_pid() {
    let bytes = make_docx(
        "<w:p><w:r><w:t>Body unaffected by a custom-property edit.</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let edited = Document::parse(&bytes)
        .expect("parse")
        .set_custom_property("MatterNumber", "M-1")
        .expect("set custom property");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    assert_opens_clean(
        &out,
        "ECMA-376 §22.3.2.2 / Annex A.6.3: docProps/custom.xml must validate \
         against CT_Property (fmtid and pid are use=\"required\") so Word opens \
         the package without repair",
    );

    let custom = custom_xml_of(&out)
        .expect("ECMA-376 §22.3.2.2: set_custom_property must produce docProps/custom.xml");
    assert!(
        custom.contains("fmtid="),
        "ECMA-376 §22.3.2.2 / A.6.3: every <property> must carry the required \
         fmtid attribute; custom.xml was: {custom}",
    );
    assert!(
        custom.contains("pid="),
        "ECMA-376 §22.3.2.2 / A.6.3: every <property> must carry the required \
         pid attribute; custom.xml was: {custom}",
    );
}
